image:
{{
  (() => {
    // 1. Get the current active record
    const active = PreviewManager.getActiveData();
    const macIp = "192.168.10.63";
    const collection = "Schematics";
    const placeholder = "https://placehold.co/600x400?text=Awaiting+Schematic";

    // 2. Multi-point Safety Check
    // Check if 'active' exists AND has both required properties to build a URL
    if (!active || !active.id || !active.Picture) {
      return placeholder;
    }

    // 3. Construct the PocketBase URL only when data is fully verified
    // Pattern: http://IP:PORT/api/files/COLLECTION/ID/FILENAME
    return `http://${macIp}:8090/api/files/${collection}/${active.id}/${active.Picture}`;
  })()
}}
